import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"三因极一病证方论","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/03-宋金元/06-三因极一病证方论（陈无择）.md","filePath":"tcm-data/03-宋金元/06-三因极一病证方论（陈无择）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/03-宋金元/06-三因极一病证方论（陈无择）.md"};function n(s,t,d,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="三因极一病证方论" tabindex="-1">三因极一病证方论 <a class="header-anchor" href="#三因极一病证方论" aria-label="Permalink to &quot;三因极一病证方论&quot;">​</a></h1><blockquote><p>陈无择（1131-1189年），浙江温州人 中医病因学集大成者，&quot;三因论&quot;的定论者 代表作：《三因极一病证方论》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名言，字无择</li><li><strong>生卒</strong>：约1131-1189年（与张元素同时代）</li><li><strong>籍贯</strong>：浙江青田（今温州）</li><li><strong>著作</strong>：《三因极一病证方论》（简称《三因方》）</li><li><strong>学术地位</strong>：<strong>将中医病因学说系统化、定型化</strong>的第一人</li></ul><h3 id="书名含义" tabindex="-1">书名含义 <a class="header-anchor" href="#书名含义" aria-label="Permalink to &quot;书名含义&quot;">​</a></h3><ul><li><strong>三因</strong>：内因、外因、不内外因</li><li><strong>极一</strong>：归于一理（所有病因最终归于一个道理）</li></ul><blockquote><p><strong>「医事之要，无出三因。」</strong></p></blockquote><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-三因论-——-中医病因学的定型" tabindex="-1">1. 三因论 —— 中医病因学的定型 <a class="header-anchor" href="#_1-三因论-——-中医病因学的定型" aria-label="Permalink to &quot;1. 三因论 —— 中医病因学的定型&quot;">​</a></h3><blockquote><p><strong>「然六淫，天之常气，冒之则先自经络流入，内合于脏腑，为外所因；七情，人之常性，动之则先自脏腑郁发，外形于肢体，为内所因；其如饮食饥饱，叫呼伤气，尽神度量，疲极筋力，阴阳违逆，乃至虎狼毒虫，金疮踒折，疰忤附着，畏压溺等，有背常理，为不内外因。」</strong></p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">分类</th><th style="text-align:left;">内容</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>内因</strong></td><td style="text-align:left;">喜、怒、忧、思、悲、恐、惊（七情）</td><td style="text-align:left;">从内而生，伤及脏腑</td></tr><tr><td style="text-align:left;"><strong>外因</strong></td><td style="text-align:left;">风、寒、暑、湿、燥、火（六淫）</td><td style="text-align:left;">从外而入，先犯经络</td></tr><tr><td style="text-align:left;"><strong>不内外因</strong></td><td style="text-align:left;">饮食、劳倦、房室、金刃、虫兽、跌仆等</td><td style="text-align:left;">非内非外，实际是&quot;其他&quot;</td></tr></tbody></table><h3 id="_2-三因归一的辨证思路" tabindex="-1">2. 三因归一的辨证思路 <a class="header-anchor" href="#_2-三因归一的辨证思路" aria-label="Permalink to &quot;2. 三因归一的辨证思路&quot;">​</a></h3><p>陈无择强调：<strong>虽有三因之分，但辨证时必须&quot;极一&quot;——归于一个统一的病机判断。</strong></p><h3 id="_3-按三因分类的方剂" tabindex="-1">3. 按三因分类的方剂 <a class="header-anchor" href="#_3-按三因分类的方剂" aria-label="Permalink to &quot;3. 按三因分类的方剂&quot;">​</a></h3><p>《三因方》共载方约1500首，按三因分类编排，每一方都注明针对哪一因。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>温胆汤</strong>（三因方版）</td><td style="text-align:left;">半夏、竹茹、枳实、陈皮、茯苓、甘草、生姜、大枣</td><td style="text-align:left;">胆虚寒，惊悸不眠</td></tr><tr><td style="text-align:left;"><strong>控涎丹</strong></td><td style="text-align:left;">甘遂、大戟、白芥子</td><td style="text-align:left;">痰涎水饮</td></tr><tr><td style="text-align:left;"><strong>蠲痹汤</strong></td><td style="text-align:left;">羌活、防风、赤芍、姜黄、当归、黄芪、甘草</td><td style="text-align:left;">风湿痹痛</td></tr><tr><td style="text-align:left;"><strong>小蓟饮子</strong></td><td style="text-align:left;">生地黄、小蓟、滑石、通草、蒲黄、淡竹叶、藕节、当归、山栀、甘草</td><td style="text-align:left;">血淋、尿血</td></tr><tr><td style="text-align:left;"><strong>五皮散</strong></td><td style="text-align:left;">生姜皮、桑白皮、大腹皮、茯苓皮、陈皮</td><td style="text-align:left;">皮水、水肿</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「医事之要，无出三因。」</strong></p></blockquote><blockquote><p><strong>「六淫，天之常气。」</strong><strong>「七情，人之常性。」</strong></p></blockquote><blockquote><p><strong>「三因既明，则病无遁情矣。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li><strong>三因论</strong>成为后世中医病因学的标准分类法——沿用至今</li><li>每本中医教材的《病因》章节，都按陈无择的三因框架编写</li><li>他对七情致病的详细论述，是中医身心医学的重要遗产</li></ul><h3 id="与黄元御的关系" tabindex="-1">与黄元御的关系 <a class="header-anchor" href="#与黄元御的关系" aria-label="Permalink to &quot;与黄元御的关系&quot;">​</a></h3><p>黄元御虽然对宋代以后的医家多有批评，但他病因分析的&quot;水寒、土湿、木郁&quot;三层次，本质上也是一种&quot;三因&quot;模型——只是换了个视角。</p><hr><p><em>本条目为精简框架版。可在后续扩展至三因方详细药解、与《内经》病因理论的对比等。</em></p>',32)])])}const f=e(r,[["render",n]]);export{c as __pageData,f as default};
